# BEFORE (wrong):
{"id":"platinum", "formula": lambda usd, fx: (usd/31.1035)*fx*1.10*1.03}

# AFTER (correct — adds *10 to match unit ₹/10g):
{"id":"platinum", "formula": lambda usd, fx: (usd/31.1035)*10*fx*1.10*1.03}
{"id":"palladium", "formula": lambda usd, fx: (usd/31.1035)*10*fx*1.10*1.03}

# Sanity check: PL=F ~1000 USD, fx=84
# Result: (1000/31.1035)*10*84*1.13 = ~30,600 INR/10g  ✓

def compute_rule_based_danger(symbol: str, df_stock) -> dict:
    closes = df_stock["Close"].dropna()
    volumes = df_stock["Volume"].dropna()
    if len(closes) < 5:
        return {"danger_score": 0, "flags": []}
    price_drop = (closes.iloc[-1] - closes.iloc[-5]) / closes.iloc[-5] * 100
    vol_ratio = volumes.iloc[-1] / volumes.iloc[-5:].mean()
    score, flags = 0, []
    if price_drop < -10: score += 40; flags.append(f"Drop {price_drop:.1f}% in 5d")
    elif price_drop < -5: score += 20; flags.append(f"Drop {price_drop:.1f}% in 5d")
    if vol_ratio > 3: score += 30; flags.append(f"Volume {vol_ratio:.1f}× avg")
    elif vol_ratio > 2: score += 15; flags.append(f"Volume {vol_ratio:.1f}× avg")
    pct_from_high = (closes.iloc[-1] - closes.max()) / closes.max() * 100
    if pct_from_high < -40: score += 20; flags.append(f"{pct_from_high:.1f}% from 52W high")
    return {"danger_score": min(score, 100), "flags": flags}
